import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useMusic } from '../../context/MusicContext'; // Import context
import { Trophy, Heart, Headphones } from 'lucide-react';

const Ranking = () => {
  const [topSongs, setTopSongs] = useState([]);
  
  // Lấy favorites và hàm like từ Context để theo dõi biến động
  const { favorites, toggleLikeGlobal } = useMusic();

  useEffect(() => {
    const fetchRanking = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/songs/ranking');
        setTopSongs(res.data);
      } catch (err) {
        console.error("Lỗi tải bảng xếp hạng:", err);
      }
    };

    fetchRanking();
    
    // Khi favorites thay đổi, useEffect này sẽ chạy lại -> dữ liệu ranking sẽ mới nhất
  }, [favorites]); 

  return (
    <div style={rankPage}>
      <header style={rankHeader}>
        <Trophy size={80} color="#FFD700" />
        <h1 style={{fontSize: '40px', margin: '10px 0', color: '#1db954'}}>TOP 10 IAMNHAC</h1>
        <p style={{color: '#b3b3b3'}}>Cập nhật thời gian thực dựa trên lượt yêu thích</p>
      </header>

      <div style={rankList}>
        {topSongs.map((song, index) => {
          const isLiked = favorites?.includes(song._id);

          return (
            <div key={song._id} style={rankItem(index)}>
              <div style={rankNumber(index)}>{index + 1}</div>
              <img src={`http://localhost:5000${song.imageUrl}`} style={rankImg} alt="" />
              
              <div style={{ flex: 1 }}>
                <div style={songName}>{song.title}</div>
                <div style={songArt}>{song.artist}</div>
              </div>

              <div style={statsContainer}>
                <div style={statItem}>
                  <Headphones size={16} color="#1db954" />
                  <span>{song.playCount || 0}</span>
                </div>

                {/* NÚT LIKE NGAY TRÊN BẢNG XẾP HẠNG */}
                <div 
                  style={{ ...statItem, cursor: 'pointer' }} 
                  onClick={() => toggleLikeGlobal(song._id)}
                >
                  <Heart 
                    size={18} 
                    fill={isLiked ? "#ff4d4d" : "none"} 
                    color={isLiked ? "#ff4d4d" : "#b3b3b3"} 
                  />
                  <span style={{ color: isLiked ? "#ff4d4d" : "#fff", minWidth: '20px' }}>
                    {song.likes?.length || 0}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- STYLES (Đảm bảo scannable) ---
const rankPage = { padding: '40px 60px', maxWidth: '900px', margin: '0 auto', paddingBottom: '120px' };
const rankHeader = { textAlign: 'center', marginBottom: '40px' };
const rankList = { background: '#181818', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.5)' };
const rankItem = (i) => ({ 
  display: 'flex', alignItems: 'center', padding: '15px 25px', color: '#fff',
  borderBottom: '1px solid #282828',
  background: i === 0 ? 'linear-gradient(90deg, #2a2200 0%, #181818 100%)' : 'transparent'
});
const rankNumber = (i) => ({ 
  fontSize: '22px', fontWeight: 'bold', width: '40px', 
  color: i === 0 ? '#FFD700' : i === 1 ? '#C0C0C0' : i === 2 ? '#CD7F32' : '#555' 
});
const rankImg = { width: '50px', height: '50px', borderRadius: '4px', marginRight: '20px', objectFit: 'cover' };
const songName = { fontSize: '16px', fontWeight: 'bold' };
const songArt = { fontSize: '13px', color: '#b3b3b3' };
const statsContainer = { display: 'flex', gap: '25px' };
const statItem = { display: 'flex', alignItems: 'center', gap: '8px', fontSize: '14px' };

export default Ranking;
